 30→// ========== 测试框架 ==========
 31→let passed = 0;
 32→let failed = 0;
 33→let cookie = '';
 34→let xsrfToken = '';
 35→
 36→function assert(name, condition, detail) {
 37→  if (condition) {
 38→    console.log(`  ✅ ${name}`);
 39→    passed++;
 40→  } else {
 41→    console.log(`  ❌ ${name}`);
 42→    if (detail !== undefined)
 43→      console.log(`     实际值:`, typeof detail === 'object'
 44→        ? JSON.stringify(detail).slice(0, 300) : detail);
 45→    failed++;
 46→  }
 47→}
