 49→// ========== HTTP 工具 ==========
 50→
 51→function parseCookies(res) {
 52→  const cookies = {};
 53→  const setCookieHeaders = res.headers.getSetCookie?.() || [];
 54→  for (const header of setCookieHeaders) {
 55→    const [kv] = header.split(';');
 56→    const eqIdx = kv.indexOf('=');
 57→    if (eqIdx > 0) {
 58→      cookies[kv.substring(0, eqIdx).trim()] = kv.substring(eqIdx + 1).trim();
 59→    }
 60→  }
 61→  return cookies;
 62→}
 63→
 64→async function rawFetch(method, url, headers = {}, body) {
 65→  const opts = { method, headers: { ...headers }, redirect: 'manual' };
 66→  if (cookie) opts.headers['cookie'] = cookie;
 67→  if (xsrfToken) opts.headers['x-xsrf-token'] = xsrfToken;
 68→  if (body) {
 69→    opts.headers['content-type'] = 'application/json';
 70→    opts.body = JSON.stringify(body);
 71→  }
 72→  return fetch(url, opts);
 73→}
 74→
 75→async function GET(path, extraHeaders = {}) {
 76→  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`, extraHeaders);
 77→  return res.json();
 78→}
 79→
 80→async function POST(path, body, extraHeaders = {}) {
 81→  const res = await rawFetch('POST', `${CONFIG.host}/api/v1${path}`, extraHeaders, body);
 82→  return res.json();
 83→}
 84→
 85→async function rawGET(path, extraHeaders = {}) {
 86→  return rawFetch('GET', `${CONFIG.host}/api/v1${path}`, extraHeaders);
 87→}
 88→
 89→// apitable API（通过 nginx 反代 /apitable/api/v1/...）
 90→async function APITABLE_GET(path, extraHeaders = {}) {
 91→  const res = await rawFetch('GET', `${CONFIG.host}/apitable/api/v1${path}`, extraHeaders);
 92→  return res.json();
 93→}
 94→
 95→async function APITABLE_POST(path, body, extraHeaders = {}) {
 96→  const res = await rawFetch('POST', `${CONFIG.host}/apitable/api/v1${path}`, extraHeaders, body);
 97→  return res.json();
 98→}
 99→
100→async function APITABLE_DELETE(path, extraHeaders = {}) {
101→  const res = await rawFetch('DELETE', `${CONFIG.host}/apitable/api/v1${path}`, extraHeaders);
102→  return res.json();
103→}
104→
105→// ========== 登录管理 ==========
106→
107→async function login(email) {
108→  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${encodeURIComponent(email)}`,
109→    { redirect: 'manual' });
110→  const cookies = parseCookies(res);
111→  // 收集所有 cookie
112→  const allCookies = (res.headers.getSetCookie?.() || [])
113→    .map(h => h.split(';')[0]).join('; ');
114→  if (cookies.JWT || cookies.SESSION || allCookies) {
115→    cookie = allCookies || (cookies.JWT ? `JWT=${cookies.JWT}` : `SESSION=${cookies.SESSION}`);
116→    xsrfToken = cookies['XSRF-TOKEN'] || '';
117→    return true;
118→  }
119→  return false;
120→}
121→
122→let savedSessions = {};
123→function saveSession(name) {
124→  savedSessions[name] = { cookie, xsrfToken };
125→}
126→function restoreSession(name) {
127→  ({ cookie, xsrfToken } = savedSessions[name]);
128→}
