136→// ---- 维度 6a：子管理员变更（type=1）写操作验证 ----
137→async function testSubAdminChangeRecord() {
138→  console.log('⚡ 6a. 子管理员变更（type=1）— 添加/移除子管理员触发变更记录');
139→  const spaceIdHeader = { 'X-Space-Id': CONFIG.spaceId };
140→
141→  // 1. 先邀请 test101 进空间站（确保有成员可以操作）
142→  const preCleanBody = {
143→    name: CONFIG.testMemberName,
144→    inviteTempInfoList: [{
145→      checked: true, spaceId: CONFIG.spaceId, spaceName: CONFIG.spaceName,
146→      teamList: [{ teamId: CONFIG.teamId, teamName: CONFIG.spaceName }],
147→    }],
148→  };
149→  // 先移除再邀请，确保干净状态
150→  await rawFetch('POST', `${CONFIG.host}/api/v1/management/invite/member/remove`, {}, preCleanBody);
151→  await sleep(2000);
152→  const inviteBody = {
153→    nameList: [CONFIG.testMemberName],
154→    inviteTempInfoList: [{
155→      checked: true, spaceId: CONFIG.spaceId, spaceName: CONFIG.spaceName,
156→      teamList: [{ teamId: CONFIG.teamId, teamName: CONFIG.spaceName }],
157→    }],
158→  };
159→  const invRes = await rawFetch('POST', `${CONFIG.host}/api/v1/management/invite/member/add`, {}, inviteBody);
160→  console.log(`  ℹ️  邀请 ${CONFIG.testMemberName} HTTP ${invRes.status}`);
161→  await sleep(3000);
162→
163→  // 2. 通过 apitable 搜索接口获取 test101 的 memberId
164→  const searchRes = await APITABLE_GET(
165→    `/org/member/search?keyword=${encodeURIComponent(CONFIG.testMemberName)}`,
166→    spaceIdHeader
167→  );
168→  console.log(`  ℹ️  搜索成员结果: ${JSON.stringify(searchRes.data?.slice?.(0, 2) || searchRes).slice(0, 300)}`);
169→
170→  let memberId = null;
171→  if (searchRes.success && searchRes.data?.length > 0) {
172→    memberId = searchRes.data[0].memberId;
173→    console.log(`  ℹ️  ${CONFIG.testMemberName} memberId = ${memberId}`);
174→  }
175→  if (!memberId) {
176→    console.log('  ⚠️  未找到测试成员 memberId，跳过子管理员变更测试');
177→    // 清理
178→    await rawFetch('POST', `${CONFIG.host}/api/v1/management/invite/member/remove`, {}, preCleanBody);
179→    return;
180→  }
181→
182→  // 3. 先尝试删除已有子管理员角色（幂等处理）
183→  await APITABLE_DELETE(`/space/deleteRole/${memberId}`, spaceIdHeader);
184→  await sleep(2000);
185→
186→  // 4. 记录 type=1 基线
187→  const baseline = await GET(`/space/changeRecord/page?type=1&pageNum=1&pageSize=1`, spaceIdHeader);
188→  const totalBaseline = baseline.data?.total || 0;
189→  console.log(`  ℹ️  type=1 基线: ${totalBaseline}`);
190→
191→  // 5. 添加子管理员（MANAGE_MEMBER 成员管理权限）
192→  const addRoleRes = await APITABLE_POST(`/space/addRole`, {
193→    memberIds: [memberId],
194→    resourceCodes: ['MANAGE_MEMBER'],
195→  }, spaceIdHeader);
196→  console.log(`  ℹ️  addRole: ${JSON.stringify(addRoleRes).slice(0, 200)}`);
197→  assert('addRole 返回 success', addRoleRes.success === true, addRoleRes);
198→
199→  await sleep(3000);
200→
201→  // 6. 验证 type=1 记录增加
202→  const afterAdd = await GET(`/space/changeRecord/page?type=1&pageNum=1&pageSize=10`, spaceIdHeader);
203→  const totalAfterAdd = afterAdd.data?.total || 0;
204→  console.log(`  ℹ️  addRole 后 type=1: ${totalAfterAdd}`);
205→  assert('添加子管理员后 type=1 记录增加', totalAfterAdd > totalBaseline,
206→    `baseline=${totalBaseline}, after=${totalAfterAdd}`);
207→
208→  if (totalAfterAdd > totalBaseline && afterAdd.data?.records?.length > 0) {
209→    const latest = afterAdd.data.records[0];
210→    assert('子管理员记录 type=1', latest.type === 1, latest.type);
211→    assert('子管理员记录 operatorName 非空', latest.operatorName?.length > 0, latest.operatorName);
212→    assert('子管理员记录 targetUserName 非空', latest.targetUserName?.length > 0, latest.targetUserName);
213→    assert('子管理员记录 description 非空', latest.description?.length > 0, latest.description);
214→  }
215→
216→  // 7. 删除子管理员
217→  const delRoleRes = await APITABLE_DELETE(`/space/deleteRole/${memberId}`, spaceIdHeader);
218→  console.log(`  ℹ️  deleteRole: ${JSON.stringify(delRoleRes).slice(0, 200)}`);
219→  assert('deleteRole 返回 success', delRoleRes.success === true, delRoleRes);
220→
221→  await sleep(3000);
222→
223→  // 8. 验证 type=1 记录再次增加
224→  const afterDel = await GET(`/space/changeRecord/page?type=1&pageNum=1&pageSize=10`, spaceIdHeader);
225→  const totalAfterDel = afterDel.data?.total || 0;
226→  console.log(`  ℹ️  deleteRole 后 type=1: ${totalAfterDel}`);
227→  assert('移除子管理员后 type=1 记录再次增加', totalAfterDel > totalAfterAdd,
228→    `afterAdd=${totalAfterAdd}, afterDel=${totalAfterDel}`);
229→
230→  // 9. 清理：移除测试成员
231→  await rawFetch('POST', `${CONFIG.host}/api/v1/management/invite/member/remove`, {}, preCleanBody);
232→  console.log('  ℹ️  已清理测试成员');
