389→// ---- 维度 2：分页边界 ----
390→async function testPagination() {
391→  console.log('\n📐 2. 分页边界');
392→
393→  // pageSize=1
394→  const p1 = await GET(`/space/changeRecord/page?pageNum=1&pageSize=1`, { 'X-Space-Id': CONFIG.spaceId });
395→  assert('pageSize=1 返回 success', p1.success === true, p1);
396→  assert('pageSize=1 最多返回1条', (p1.data?.records?.length || 0) <= 1);
397→
398→  // pageSize=100
399→  const p100 = await GET(`/space/changeRecord/page?pageNum=1&pageSize=100`, { 'X-Space-Id': CONFIG.spaceId });
400→  assert('pageSize=100 返回 success', p100.success === true);
401→
402→  // total 与 records 一致性
403→  if (p100.data?.total <= 100 && p100.data?.total > 0) {
404→    assert('total <= 100 时 length === total',
405→      p100.data.records.length === p100.data.total,
406→      `length=${p100.data.records.length}, total=${p100.data.total}`);
407→  }
408→
409→  // 超出最后一页
410→  const overPage = await GET(`/space/changeRecord/page?pageNum=9999&pageSize=25`, { 'X-Space-Id': CONFIG.spaceId });
411→  assert('超页返回 success', overPage.success === true);
412→  assert('超页返回空列表', (overPage.data?.records?.length || 0) === 0);
413→  assert('超页 total 不变', overPage.data?.total === p100.data?.total,
414→    `overPage.total=${overPage.data?.total}, expected=${p100.data?.total}`);
415→
416→  // 两页不重复
417→  if (p1.data?.total > 1) {
418→    const p2 = await GET(`/space/changeRecord/page?pageNum=2&pageSize=1`, { 'X-Space-Id': CONFIG.spaceId });
419→    assert('第2页有数据', (p2.data?.records?.length || 0) > 0);
420→    if (p1.data?.records?.[0] && p2.data?.records?.[0]) {
